// Normaliza y valida el input recibido desde frontend
const body = $json.body || $json;

const nombre = String(body.nombre || 'Paciente').trim();
const sintoma = String(body.sintoma || body.sintomas || '').trim();
const planSeguro = String(body.planSeguro || body.plan || 'Basico').trim();

if (!sintoma || sintoma.length < 3) {
  return [{
    json: {
      error: true,
      statusCode: 400,
      mensaje: 'Debes enviar un síntoma válido.',
      ejemplo: {
        nombre: 'Juan',
        sintoma: 'dolor de pecho y mareos',
        planSeguro: 'Premium'
      }
    }
  }];
}

const planesPermitidos = ['Basico', 'Estándar', 'Estandar', 'Premium'];
const planNormalizado = planSeguro.toLowerCase().includes('premium')
  ? 'Premium'
  : planSeguro.toLowerCase().includes('est')
    ? 'Estándar'
    : 'Basico';

return [{
  json: {
    error: false,
    nombre,
    sintoma,
    planSeguro: planNormalizado,
    timestamp: new Date().toISOString()
  }
}];

