const input = $input.first().json;

let aiText = null;
let parsed = null;

try {
  aiText = input.candidates?.[0]?.content?.parts?.[0]?.text;

  if (typeof aiText === "string") {
    aiText = aiText
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();

    parsed = JSON.parse(aiText);
  }
} catch (error) {
  parsed = null;
}

const original = $('02 Code - Validar y normalizar input').first().json;

function fallbackClasificacion(sintoma) {
  const s = (sintoma || "").toLowerCase();

  if (s.includes("pecho") || s.includes("corazón") || s.includes("cardio")) {
    return {
      especialidad: "Cardiología",
      urgencia: "alta",
      razon: "Los síntomas pueden estar relacionados con el sistema cardiovascular.",
      sintomasClave: [sintoma]
    };
  }

  if (s.includes("mareo") || s.includes("desmayo") || s.includes("cabeza") || s.includes("convuls")) {
    return {
      especialidad: "Neurología",
      urgencia: "media",
      razon: "Los síntomas pueden estar relacionados con el sistema neurológico.",
      sintomasClave: [sintoma]
    };
  }

  if (s.includes("tos") || s.includes("respirar") || s.includes("fiebre") || s.includes("pulmón")) {
    return {
      especialidad: "Neumología",
      urgencia: "media",
      razon: "Los síntomas pueden estar relacionados con el sistema respiratorio.",
      sintomasClave: [sintoma]
    };
  }

  if (s.includes("estómago") || s.includes("vomito") || s.includes("vómito") || s.includes("diarrea") || s.includes("abdominal")) {
    return {
      especialidad: "Gastroenterología",
      urgencia: "media",
      razon: "Los síntomas pueden estar relacionados con el sistema digestivo.",
      sintomasClave: [sintoma]
    };
  }

  if (s.includes("piel") || s.includes("alergia") || s.includes("roncha") || s.includes("picazón")) {
    return {
      especialidad: "Dermatología",
      urgencia: "baja",
      razon: "Los síntomas pueden estar relacionados con la piel o una reacción alérgica.",
      sintomasClave: [sintoma]
    };
  }

  if (s.includes("fractura") || s.includes("golpe") || s.includes("hueso") || s.includes("torcedura")) {
    return {
      especialidad: "Traumatología",
      urgencia: "media",
      razon: "Los síntomas pueden estar relacionados con una lesión física.",
      sintomasClave: [sintoma]
    };
  }

  return {
    especialidad: "Medicina General",
    urgencia: "baja",
    razon: "Los síntomas no permiten identificar una especialidad específica en este MVP.",
    sintomasClave: [sintoma]
  };
}

const clasificacion = parsed || fallbackClasificacion(original.sintoma);

return [
  {
    json: {
      ...original,
      especialidad: clasificacion.especialidad || "Medicina General",
      urgencia: clasificacion.urgencia || "baja",
      razon: clasificacion.razon || "Clasificación generada por el agente.",
      sintomasClave: clasificacion.sintomasClave || [original.sintoma],
      fuenteClasificacion: parsed ? "ia_gemini" : "fallback_reglas"
    }
  }
];

const data = $input.first()?.json || {};

const nombre = data.nombre || "Paciente";
const sintoma = data.sintoma || "síntomas no especificados";
const planSeguro = data.planSeguro || "Basico";

const especialidad = data.especialidad || "Medicina General";
const urgencia = data.urgencia || "baja";
const razon = data.razon || "Clasificación generada por el agente.";
const fuenteClasificacion = data.fuenteClasificacion || "fallback_reglas";
const sintomasClave = data.sintomasClave || [sintoma];

const planes = {
  Basico: {
    cobertura: 0.60,
    copagoBase: 45
  },
  Estandar: {
    cobertura: 0.75,
    copagoBase: 30
  },
  Premium: {
    cobertura: 0.90,
    copagoBase: 20
  }
};

const hospitales = [
  {
    nombre: "Hospital Central",
    especialidades: ["Cardiología", "Neurología", "Medicina General"],
    costoConsulta: 280
  },
  {
    nombre: "Clínica San Rafael",
    especialidades: ["Neumología", "Gastroenterología", "Medicina General"],
    costoConsulta: 240
  },
  {
    nombre: "Centro Médico Vida",
    especialidades: ["Dermatología", "Medicina General"],
    costoConsulta: 180
  },
  {
    nombre: "Hospital Metropolitano",
    especialidades: ["Traumatología", "Cardiología", "Medicina General"],
    costoConsulta: 300
  }
];

const plan = planes[planSeguro] || planes.Basico;

const hospitalesCompatibles = hospitales.filter(hospital =>
  hospital.especialidades.includes(especialidad)
);

const opciones = hospitalesCompatibles.length > 0
  ? hospitalesCompatibles
  : hospitales.filter(hospital => hospital.especialidades.includes("Medicina General"));

let hospitalRecomendado = opciones[0];

for (const hospital of opciones) {
  if (hospital.costoConsulta < hospitalRecomendado.costoConsulta) {
    hospitalRecomendado = hospital;
  }
}

const costoPacienteEstimado = Math.round(
  hospitalRecomendado.costoConsulta * (1 - plan.cobertura)
);

const copago = plan.copagoBase;

const mensaje = `Hola ${nombre}. Según tu plan ${planSeguro}, la especialidad sugerida es ${especialidad}. Tu copago estimado es de $${copago} y el hospital más conveniente es ${hospitalRecomendado.nombre}, con costo estimado para paciente de $${costoPacienteEstimado}. Importante: por la naturaleza de los síntomas, se recomienda buscar atención médica urgente o acudir a emergencias.`;

return [
  {
    json: {
      nombre,
      especialidad,
      urgencia,
      cobertura: `${Math.round(plan.cobertura * 100)}%`,
      copago: `$${copago}`,
      hospitalRecomendado: hospitalRecomendado.nombre,
      costoPacienteEstimado: `$${costoPacienteEstimado}`,
      fuenteClasificacion,
      razon,
      mensaje,
      disclaimer: "MVP de hackathon. No reemplaza diagnóstico médico profesional.",
      metadata: {
        planSeguro,
        sintomasRecibidos: sintoma,
        sintomasClave,
        timestamp: new Date().toISOString()
      }
    }
  }
];
